const aiOutput = $input.first().json.output || '';

const match = aiOutput.match(/\[CHARTS_JSON\]([\s\S]*?)\[\/CHARTS_JSON\]/);
if (!match) return [];

let raw = match[1].trim();
// Strip markdown fences
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();

function repairJson(s) {
  // Remove JS single-line comments
  s = s.replace(/\/\/[^\n]*/g, '');
  // Remove JS block comments
  s = s.replace(/\/\*[\s\S]*?\*\//g, '');
  // Trailing commas before ] or }
  s = s.replace(/,\s*([\]\}])/g, '$1');
  // Replace single quotes used as string delimiters (simple cases)
  // (skip вЂ” too risky, leave as-is)
  return s.trim();
}

let charts;
try {
  charts = JSON.parse(raw);
} catch (e) {
  try {
    charts = JSON.parse(repairJson(raw));
  } catch (e2) {
    // Parsing failed entirely вЂ” return no items so QuickChart is never called
    return [];
  }
}

if (!Array.isArray(charts) || charts.length === 0) return [];

return charts
  .filter(c => c && c.chartConfig && c.chartConfig.data)
  .map(c => ({ json: { sheetName: c.sheetName || 'chart', chartConfig: c.chartConfig } }));

// Code node runs ONCE for all items вЂ” iterate with .map()
const allItems  = $input.all();
const allCharts = $('Parse AI Chart Configs1').all();

return allItems.map((item, idx) => {
  const sheetName = allCharts[idx]?.json?.sheetName || ('chart_' + idx);
  return { json: { sheetName }, binary: item.binary };
});
